const payload = $json.body ?? $json;
const lead = payload.lead ?? {};
const employee = payload.employee ?? {};
const ghl = payload.ghl ?? {};

return [
  {
    json: {
      event: payload.event ?? 'ai_employee.lead_synced',
      received_at: new Date().toISOString(),
      employee_id: employee.id ?? null,
      employee_name: employee.name ?? null,
      employee_type: employee.type ?? null,
      lead_id: lead.id ?? null,
      lead_name: lead.name ?? null,
      lead_email: lead.email ?? null,
      lead_phone: lead.phone ?? null,
      lead_status: lead.status ?? null,
      service_needed: lead.service_needed ?? null,
      ghl_contact_id: ghl.contactId ?? lead.ghl_contact_id ?? null,
      ghl_opportunity_id: ghl.opportunityId ?? lead.ghl_opportunity_id ?? null,
      next_step: lead.preferred_time ? 'appointment_requested' : lead.status === 'qualified' ? 'sales_review' : 'follow_up',
      source_app: payload.source_app ?? 'OBMC AI Employees'
    }
  }
];
